#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        double x[n], p, q;
        for (int i = 0; i < n; i++) {
            scanf("%lf", &x[i]);
        }
        scanf("%lf %lf", &p, &q);
        double max_sum = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                double angle1 = atan2(q, x[i] - p);
                double angle2 = atan2(q, x[j] - p);
                double sum = fabs(angle1 - angle2);
                if (sum > max_sum) {
                    max_sum = sum;
                }
            }
        }
        printf("%.6f\n", max_sum);
    }
    return 0;
}

