        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            double[] x = new double[n];
            for (int i = 0; i < n; i++) {
                x[i] = sc.nextDouble();
            }
            double p = sc.nextDouble();
            double q = sc.nextDouble();
            double max_sum = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    double angle1 = Math.atan2(q, x[i] - p);
                    double angle2 = Math.atan2(q, x[j] - p);
                    double sum = Math.abs(angle1 - angle2);
                    if (sum > max_sum) {
                        max_sum = sum;
                    }
                }
            }
            System.out.printf("%.6f\n", max_sum);
